class Solution:
    def maximumLength(self, s: str) -> int:
        from collections import defaultdict

        n = len(s)
        count = defaultdict(int)

        # Count all special substrings
        for i in range(n):
            for j in range(i + 1, n + 1):
                if all(c == s[i] for c in s[i:j]):
                    count[s[i:j]] += 1

        # Find the maximum length of a special substring that appears at least 3 times
        max_len = -1
        for substr, freq in count.items():
            if freq >= 3:
                max_len = max(max_len, len(substr))

        return max_len
